		return false;
	}
	else 
		processData();

	return true;
}

bool ModelManager::recursive_render(const struct aiScene *sc, const struct aiNode* nd/*, float scale*/)
{
	unsigned int i;
	unsigned int n = 0, t;

	aiFace *face;

	// draw all meshes assigned to this node
	for (; n < nd->mNumMeshes; ++n)
	{
		const struct aiMesh* mesh = sc->mMeshes[nd->mMeshes[n]];

		//apply_material(sc->mMaterials[mesh->mMaterialIndex]);


		for (t = 0; t < mesh->mNumFaces; ++t) {
			const struct aiFace* face = &mesh->mFaces[t];

			for (i = 0; i < face->mNumIndices; i++)		// go through all vertices in face
			{
				int vertexIndex = face->mIndices[i];	// get group index for current index

				vertexBuff.push_back(mesh->mVertices[vertexIndex].x);
				vertexBuff.push_back(mesh->mVertices[vertexIndex].y);
				vertexBuff.push_back(mesh->mVertices[vertexIndex].z);

				vertexBuff.push_back(mesh->mNormals[vertexIndex].x);
				vertexBuff.push_back(mesh->mNormals[vertexIndex].y);
				vertexBuff.push_back(mesh->mNormals[vertexIndex].z);

				if (mesh->HasTextureCoords(0))		//HasTextureCoords(texture_coordinates_set)
				{
					vertexBuff.push_back(mesh->mTextureCoords[0][vertexIndex].x);
					vertexBuff.push_back(mesh->mTextureCoords[0][vertexIndex].y);
					//mTextureCoords[channel][vertex]
				}
				else
				{
					vertexBuff.push_back(0);
					vertexBuff.push_back(0);
				}
				face = &mesh->mFaces[t];
				indexBuff.push_back(face->mIndices[i]);
			}
			//face = &mesh->mFaces[t];
			//indexBuff.push_back(face->mIndices[0]);
			//indexBuff.push_back(face->mIndices[1]);
			//indexBuff.push_back(face->mIndices[2]);


		}
	}

	// draw all children
	for (n = 0; n < nd->mNumChildren; ++n)
	{
		recursive_render(sc, nd->mChildren[n]/*, scale*/);
	}

	return true;
}

bool ModelManager::processData()
{
	bool repeat = true;

		recursive_render(modelScene, modelScene->mRootNode);

	return true;
}

std::vector<float> *ModelManager::getVertexData()
{
	return &vertexBuff;
}

std::vector<uint16_t> *ModelManager::getIndexData()
{
	return &indexBuff;
}
bool ModelManager::hasmaterial()
{
	bool materialcheck = modelScene->HasMaterials();
	if (materialcheck)
